/**
 * Email notification adapter — delivers notifications via email.
 *
 * Features:
 * - Template rendering: maps notification types to HTML email templates
 * - Recipient resolution: resolves user IDs to email addresses via a pluggable resolver
 * - Retry-aware result reporting
 *
 * The adapter conforms to the NotificationAdapter interface and never throws —
 * all errors are captured in the NotificationResult.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

// ---------------------------------------------------------------------------
// Email template types
// ---------------------------------------------------------------------------

export interface EmailTemplate {
  /** Render an HTML email body from a notification payload */
  render(payload: NotificationPayload): string;
}

/**
 * Built-in email templates keyed by notification type.
 * Each template produces a simple HTML email body.
 */
const defaultTemplates: Record<NotificationType, EmailTemplate> = {
  'order-confirmation': {
    render(payload) {
      const items = payload.metadata?.['items'] as string | undefined;
      const total = payload.metadata?.['total'] as string | undefined;
      return [
        '<html><body>',
        `<h1>Order Confirmation</h1>`,
        `<p>Hello,</p>`,
        `<p>${escapeHtml(payload.body)}</p>`,
        items ? `<p><strong>Items:</strong> ${escapeHtml(items)}</p>` : '',
        total ? `<p><strong>Total:</strong> ${escapeHtml(total)}</p>` : '',
        `<p>Thank you for your order!</p>`,
        '</body></html>',
      ].join('\n');
    },
  },

  'order-status-update': {
    render(payload) {
      const previousStatus = payload.metadata?.['previousStatus'] as string | undefined;
      const newStatus = payload.metadata?.['newStatus'] as string | undefined;
      return [
        '<html><body>',
        `<h1>Order Status Update</h1>`,
        `<p>${escapeHtml(payload.body)}</p>`,
        previousStatus && newStatus
          ? `<p>Status changed from <strong>${escapeHtml(previousStatus)}</strong> to <strong>${escapeHtml(newStatus)}</strong>.</p>`
          : '',
        '</body></html>',
      ].join('\n');
    },
  },

  welcome: {
    render(payload) {
      const name = payload.metadata?.['userName'] as string | undefined;
      return [
        '<html><body>',
        `<h1>Welcome to TaskFlow Pro!</h1>`,
        name ? `<p>Hi ${escapeHtml(name)},</p>` : '<p>Hi,</p>',
        `<p>${escapeHtml(payload.body)}</p>`,
        `<p>We're glad to have you on board.</p>`,
        '</body></html>',
      ].join('\n');
    },
  },

  'user-updated': {
    render(payload) {
      return [
        '<html><body>',
        `<h1>Account Updated</h1>`,
        `<p>${escapeHtml(payload.body)}</p>`,
        '</body></html>',
      ].join('\n');
    },
  },
};

// ---------------------------------------------------------------------------
// Recipient resolver
// ---------------------------------------------------------------------------

/**
 * Resolves a recipient identifier to an email address.
 * If the recipient is already an email, it is returned as-is.
 * Implement this interface to look up emails from user IDs, etc.
 */
export interface RecipientResolver {
  resolve(recipient: string): Promise<string | null>;
}

/**
 * Default resolver: treats the recipient as an email address if it contains '@',
 * otherwise returns null (unresolvable).
 */
export class DefaultRecipientResolver implements RecipientResolver {
  async resolve(recipient: string): Promise<string | null> {
    if (recipient.includes('@')) {
      return recipient;
    }
    return null;
  }
}

// ---------------------------------------------------------------------------
// Email transport
// ---------------------------------------------------------------------------

/**
 * Represents a rendered email ready for delivery.
 */
export interface EmailMessage {
  to: string;
  subject: string;
  body: string;
  htmlBody: string;
  sentAt: Date;
}

/**
 * Transport interface — abstracts the actual email sending mechanism.
 * Swap implementations for SMTP, SES, SendGrid, etc.
 */
export interface EmailTransport {
  sendMail(message: EmailMessage): Promise<void>;
}

/**
 * In-memory transport that stores sent emails for inspection (testing / dev).
 */
export class InMemoryEmailTransport implements EmailTransport {
  private sent: EmailMessage[] = [];

  async sendMail(message: EmailMessage): Promise<void> {
    this.sent.push(message);
  }

  getSentEmails(): EmailMessage[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

// ---------------------------------------------------------------------------
// EmailAdapter
// ---------------------------------------------------------------------------

export interface EmailAdapterOptions {
  transport?: EmailTransport;
  recipientResolver?: RecipientResolver;
  templates?: Partial<Record<NotificationType, EmailTemplate>>;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;
  private recipientResolver: RecipientResolver;
  private templates: Record<NotificationType, EmailTemplate>;

  constructor(options: EmailAdapterOptions = {}) {
    this.transport = options.transport ?? new InMemoryEmailTransport();
    this.recipientResolver = options.recipientResolver ?? new DefaultRecipientResolver();
    this.templates = { ...defaultTemplates, ...options.templates };
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Resolve recipient to an email address
      const resolvedEmail = await this.recipientResolver.resolve(payload.recipient);
      if (!resolvedEmail) {
        this.logger.warn(`Could not resolve recipient: ${payload.recipient}`);
        return {
          notificationId: payload.id,
          channel: 'email',
          success: false,
          error: `Could not resolve recipient "${payload.recipient}" to an email address`,
          deliveredAt: new Date(),
        };
      }

      // 2. Render the email body using the template for this notification type
      const template = this.templates[payload.type];
      const htmlBody = template.render(payload);

      // 3. Build the email message
      const email: EmailMessage = {
        to: resolvedEmail,
        subject: payload.subject,
        body: payload.body,
        htmlBody,
        sentAt: new Date(),
      };

      // 4. Send through the transport
      await this.transport.sendMail(email);

      this.logger.info(`Email sent to ${resolvedEmail}: ${payload.subject}`);

      return {
        notificationId: payload.id,
        channel: 'email',
        success: true,
        deliveredAt: email.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);

      return {
        notificationId: payload.id,
        channel: 'email',
        success: false,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /** Get all sent emails (delegates to transport if it supports inspection). */
  getSentEmails(): EmailMessage[] {
    if (this.transport instanceof InMemoryEmailTransport) {
      return this.transport.getSentEmails();
    }
    return [];
  }

  /** Clear sent emails (delegates to transport if it supports it). */
  clearSentEmails(): void {
    if (this.transport instanceof InMemoryEmailTransport) {
      this.transport.clear();
    }
  }
}

// ---------------------------------------------------------------------------
// Utility
// ---------------------------------------------------------------------------

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

