import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryEmailTransport,
  DefaultRecipientResolver,
} from '../../src/adapters/email.adapter.js';
import type {
  RecipientResolver,
  EmailTransport,
  EmailTemplate,
  EmailMessage,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date('2026-01-01'),
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let transport: InMemoryEmailTransport;
  let adapter: EmailAdapter;

  beforeEach(() => {
    transport = new InMemoryEmailTransport();
    adapter = new EmailAdapter({ transport });
  });

  describe('channel', () => {
    it('should report channel as email', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('send()', () => {
    it('should send an email and return a successful result', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should deliver the email through the transport', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
      expect(emails[0]?.body).toContain('Widget x2');
    });

    it('should render an HTML body using the template', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('<html>');
      expect(emails[0]?.htmlBody).toContain('<h1>Order Confirmation</h1>');
      expect(emails[0]?.htmlBody).toContain('Widget x2');
    });

    it('should include metadata items and total in order-confirmation template', async () => {
      const payload = makePayload({
        metadata: { items: 'Widget x2, Gadget x1', total: '$45.00' },
      });
      await adapter.send(payload);

      const html = transport.getSentEmails()[0]?.htmlBody ?? '';
      expect(html).toContain('Widget x2, Gadget x1');
      expect(html).toContain('$45.00');
    });

    it('should render order-status-update template', async () => {
      const payload = makePayload({
        type: 'order-status-update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
        metadata: { previousStatus: 'pending', newStatus: 'confirmed' },
      });
      await adapter.send(payload);

      const html = transport.getSentEmails()[0]?.htmlBody ?? '';
      expect(html).toContain('<h1>Order Status Update</h1>');
      expect(html).toContain('pending');
      expect(html).toContain('confirmed');
    });

    it('should render welcome template', async () => {
      const payload = makePayload({
        type: 'welcome',
        subject: 'Welcome to TaskFlow Pro',
        body: 'Welcome, Alice! Your account has been created.',
        metadata: { userName: 'Alice' },
      });
      await adapter.send(payload);

      const html = transport.getSentEmails()[0]?.htmlBody ?? '';
      expect(html).toContain('<h1>Welcome to TaskFlow Pro!</h1>');
      expect(html).toContain('Hi Alice,');
    });

    it('should render user-updated template', async () => {
      const payload = makePayload({
        type: 'user-updated',
        subject: 'Account Updated',
        body: 'Your profile has been updated.',
      });
      await adapter.send(payload);

      const html = transport.getSentEmails()[0]?.htmlBody ?? '';
      expect(html).toContain('<h1>Account Updated</h1>');
      expect(html).toContain('Your profile has been updated.');
    });

    it('should escape HTML in payload body', async () => {
      const payload = makePayload({
        body: 'Order for <script>alert("xss")</script>',
      });
      await adapter.send(payload);

      const html = transport.getSentEmails()[0]?.htmlBody ?? '';
      expect(html).not.toContain('<script>');
      expect(html).toContain('&lt;script&gt;');
    });
  });

  describe('recipient resolution', () => {
    it('should resolve email addresses (containing @)', async () => {
      const payload = makePayload({ recipient: 'bob@example.com' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(transport.getSentEmails()[0]?.to).toBe('bob@example.com');
    });

    it('should fail when recipient cannot be resolved', async () => {
      // DefaultRecipientResolver returns null for non-email strings
      const payload = makePayload({ recipient: 'user-123' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Could not resolve recipient');
      expect(transport.getSentEmails()).toHaveLength(0);
    });

    it('should use a custom recipient resolver', async () => {
      const customResolver: RecipientResolver = {
        async resolve(recipient: string) {
          if (recipient === 'user-42') return 'resolved@example.com';
          return null;
        },
      };

      const customAdapter = new EmailAdapter({ transport, recipientResolver: customResolver });
      const payload = makePayload({ recipient: 'user-42' });
      const result = await customAdapter.send(payload);

      expect(result.success).toBe(true);
      expect(transport.getSentEmails()[0]?.to).toBe('resolved@example.com');
    });
  });

  describe('custom templates', () => {
    it('should allow overriding templates per notification type', async () => {
      const customTemplate: EmailTemplate = {
        render() {
          return '<html><body><p>Custom template!</p></body></html>';
        },
      };

      const customAdapter = new EmailAdapter({
        transport,
        templates: { 'order-confirmation': customTemplate },
      });

      const payload = makePayload();
      await customAdapter.send(payload);

      const html = transport.getSentEmails()[0]?.htmlBody ?? '';
      expect(html).toContain('Custom template!');
      expect(html).not.toContain('<h1>Order Confirmation</h1>');
    });
  });

  describe('error handling', () => {
    it('should return a failed result when transport throws', async () => {
      const failingTransport: EmailTransport = {
        async sendMail() {
          throw new Error('SMTP connection refused');
        },
      };

      const failAdapter = new EmailAdapter({ transport: failingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
      expect(result.notificationId).toBe('notif-0001');
    });

    it('should handle non-Error thrown values', async () => {
      const failingTransport: EmailTransport = {
        async sendMail() {
          throw 'string error';
        },
      };

      const failAdapter = new EmailAdapter({ transport: failingTransport });
      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('string error');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return sent emails from the in-memory transport', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ id: 'notif-0002', recipient: 'bob@example.com' }));

      expect(adapter.getSentEmails()).toHaveLength(2);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();

      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return empty array when transport is not InMemoryEmailTransport', () => {
      const customTransport: EmailTransport = { async sendMail() {} };
      const customAdapter = new EmailAdapter({ transport: customTransport });

      expect(customAdapter.getSentEmails()).toEqual([]);
    });
  });
});

describe('DefaultRecipientResolver', () => {
  const resolver = new DefaultRecipientResolver();

  it('should resolve strings containing @', async () => {
    expect(await resolver.resolve('test@example.com')).toBe('test@example.com');
  });

  it('should return null for strings without @', async () => {
    expect(await resolver.resolve('user-123')).toBeNull();
  });
});

describe('InMemoryEmailTransport', () => {
  let transport: InMemoryEmailTransport;

  beforeEach(() => {
    transport = new InMemoryEmailTransport();
  });

  it('should store sent emails', async () => {
    const msg: EmailMessage = {
      to: 'test@example.com',
      subject: 'Test',
      body: 'plain body',
      htmlBody: '<p>html body</p>',
      sentAt: new Date(),
    };
    await transport.sendMail(msg);

    expect(transport.getSentEmails()).toHaveLength(1);
    expect(transport.getSentEmails()[0]?.to).toBe('test@example.com');
  });

  it('should clear stored emails', async () => {
    await transport.sendMail({
      to: 'a@b.com',
      subject: 's',
      body: 'b',
      htmlBody: '<p>b</p>',
      sentAt: new Date(),
    });
    transport.clear();
    expect(transport.getSentEmails()).toHaveLength(0);
  });
});

